const TOKEN_ALIASES = {
  pyaaz: 'onion', piaz: 'onion', kanda: 'onion', peyaj: 'onion', vengayam: 'onion', onoin: 'onion',
  aloo: 'potato', alu: 'potato', batata: 'potato',
  tamatar: 'tomato', tamato: 'tomato', tamoto: 'tomato',
  doodh: 'milk', chawal: 'rice', anda: 'egg', ande: 'egg', mutta: 'egg', dim: 'egg',
  maggie: 'maggi', magi: 'maggi',
};
const UNIT_ALIASES = { kg: 'kg', kilo: 'kg', kilogram: 'kg', g: 'g', gm: 'g', gram: 'g', l: 'l', litre: 'l', liter: 'l', ltr: 'l', ml: 'ml' };

function compactUnits(value) {
  return String(value || '')
    .replace(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilogram|g|gm|gram|ml|l|ltr|litre|liter)\b/gi, (_, num, unit) => num + (UNIT_ALIASES[String(unit).toLowerCase()] || String(unit).toLowerCase()))
    .replace(/[\u2013\u2014-]+/g, ' ')
    .replace(/[()_,/]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeToken(token) {
  const raw = compactUnits(token).toLowerCase().replace(/[^a-z0-9.]+/g, ' ').trim();
  if (!raw) return '';
  const mapped = TOKEN_ALIASES[raw] || raw;
  if (mapped.endsWith('ies') && mapped.length > 4) return mapped.slice(0, -3) + 'y';
  if (mapped.endsWith('oes') && mapped.length > 4) return mapped.slice(0, -2);
  if (mapped.endsWith('ses') && mapped.length > 4) return mapped.slice(0, -2);
  if (mapped.endsWith('s') && !mapped.endsWith('ss') && mapped.length > 3) return mapped.slice(0, -1);
  return mapped;
}

function normalizeName(value) {
  return compactUnits(value)
    .split(/\s+/)
    .filter(Boolean)
    .map((token) => normalizeToken(token))
    .filter(Boolean)
    .join(' ')
    .trim();
}

const root = (() => {
  try {
    const current = $input.first();
    if (current && current.json) return current.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  return {};
})();

// tool_input is JSON-stringified by convertFieldsToString — parse it back
let input;
const rawTi = root.tool_input;
if (rawTi && typeof rawTi === 'object') {
  input = rawTi;
} else if (rawTi && typeof rawTi === 'string' && rawTi.startsWith('{')) {
  try { input = JSON.parse(rawTi); } catch { input = root; }
} else {
  input = root;
}

const rawQuery = String(input.product_name || input.raw_message || '').trim();
const normalizedSearch = normalizeName(rawQuery);
const suffixQtyMatch = !input.quantity_hint && rawQuery.match(/^(.+?)\s+(\d+(?:\.\d+)?)$/);
const suffixSearch = suffixQtyMatch ? normalizeName(suffixQtyMatch[1]) : '';
const suffixQty = suffixQtyMatch ? Number(suffixQtyMatch[2]) : null;
const quantity = Number(input.quantity ?? 1) || 1;

function esc(value) {
  return String(value || '').replace(/'/g, "''");
}

return [{
  json: {
    normalized_search: normalizedSearch,
    secondary_search: suffixSearch,
    suffix_quantity_candidate: suffixQty,
    sku_direct: String(input.sku_direct || '').trim(),
    chat_id: input.chat_id,
    product_name: rawQuery,
    quantity,
    quantity_hint: input.quantity_hint ?? null,
    quantity_hint_position: input.quantity_hint_position || '',
    mode: input.mode || 'add',
    primary_search_sql: esc(normalizedSearch),
    secondary_search_sql: esc(suffixSearch),
    sku_sql: esc(String(input.sku_direct || '').trim()),
  },
}];

const input = $('Normalize Search Term').first().json;
const rows = $input.all().map((item) => item.json).filter((row) => row && (row.sku || row.item_name));
const runtimeSource = Buffer.from("", 'base64').toString('utf8');
const rawResult = eval('(function(input, rows){\n' + runtimeSource + '\n})(input, rows)');
if (!rawResult || typeof rawResult !== 'object' || Array.isArray(rawResult)) throw new Error('Pick Best Match must resolve to an object');
return [{ json: rawResult }];

const input = $('Normalize Search Term').first().json;
const name = input.product_name || input.normalized_search;
const body = 'I could not find "' + name + '" in this store right now.\n\nTry the pack or size, for example "Eggs 10" or "Amul Milk 500ml". You can also send multiple items like "2 milk and 1 bread".';
return [{ json: {
  chat_id: input.chat_id,
  customer_ui_state: 'BROWSE_HOME',
  message_type: 'list',
  body_text: 'Item not found\n\n' + body,
  list_sections: [{
    title: 'What next?',
    rows: [
      { id: 'start_shopping', title: 'Shop items', description: 'Browse category picks' },
      { id: 'get_promos', title: 'Offers', description: 'See active savings' },
      { id: 'view_cart', title: 'View cart', description: 'Check your current cart' },
    ],
  }],
} }];

const input = $('Normalize Search Term').first().json;
const match = $('Pick Best Match').first().json;
if (match.match_status === 'ambiguous') {
  const qty = Number(match.requested_quantity || input.quantity || 1);
  const candidates = Array.isArray(match.candidate_rows) ? match.candidate_rows : [];
  const title = 'Choose the closest item for "' + (match.query_label || input.product_name || input.normalized_search) + '"';
  if (Number(input.quantity || 1) <= 0 || String(input.mode || '') === 'remove') {
    const options = (match.matches || []).slice(0, 5).map((label) => '- ' + label).join('\n');
    return [{ json: {
      chat_id: input.chat_id,
      customer_ui_state: 'CART_ACTIVE',
      message_type: 'text',
      body_text: title + '.\n' + options + '\n\nPlease reply with the exact item name to remove it safely.',
      buttons: [],
    } }];
  }
  if (candidates.length > 0 && candidates.length <= 2) {
    return [{ json: {
      chat_id: input.chat_id,
      customer_ui_state: 'ITEM_QUANTITY_PICKER',
      message_type: 'button',
      body_text: title + '.\n\nI will add quantity ' + qty + ' after you choose one.',
      buttons: candidates.map((candidate) => ({
        id: 'add_qty__' + candidate.sku + '__' + qty,
        title: String(candidate.item_name || '').slice(0, 20),
      })),
    } }];
  }
  return [{ json: {
    chat_id: input.chat_id,
    customer_ui_state: 'ITEM_QUANTITY_PICKER',
    message_type: 'list',
    body_text: title + '.\n\nI will add quantity ' + qty + ' after you choose an item.',
    list_sections: [{
      title: 'Matching products',
      rows: candidates.slice(0, 5).map((candidate) => ({
        id: 'add_qty__' + candidate.sku + '__' + qty,
        title: String(candidate.item_name || '').slice(0, 24),
        description: (() => {
        try { const ep = $('Search Products').first().json.enable_pricing; if (ep === false) return (Number(candidate.stock || 0) + ' ' + (candidate.unit || 'pcs') + ' in stock').slice(0, 72); } catch {}
        return ('₹' + Number(candidate.price || 0).toFixed(0) + ' • ' + Number(candidate.stock || 0) + ' ' + (candidate.unit || 'pcs') + ' in stock').slice(0, 72);
      })(),
      })),
    }],
    buttons: [],
  } }];
}
const body = match.item_name + ' is out of stock right now.\n\nChoose another item or keep shopping.';
return [{ json: {
  chat_id: input.chat_id,
  customer_ui_state: 'BROWSE_HOME',
  message_type: 'button',
  body_text: body,
  buttons: [
    { id: 'start_shopping', title: 'Shop Items' },
    { id: 'view_cart', title: 'View Cart' },
  ],
} }];

