WHERE cart_id = (
  SELECT cart_id FROM public.carts
  WHERE user_id = {{ $('Normalize Search Term').first().json.chat_id }} AND status = 'active' LIMIT 1
) AND sku = '{{ $('Pick Best Match').first().json.sku }}';

