const product = $('Pick Best Match').first().json;
const input = $('Normalize Search Term').first().json;
const enablePricing = (() => {
  try { return $('Search Products').first().json.enable_pricing !== false; } catch { return true; }
})();
const total = Number($('Get Cart After Remove').first().json.total || 0);
const totalStr = enablePricing ? ' | Cart: ₹' + total.toFixed(0) : '';
const body = `🗑 ${product.item_name} removed${totalStr}`;
return [{ json: { chat_id: input.chat_id, message_type: 'text', body_text: body, buttons: [] } }];

const input = $('Normalize Search Term').first().json;
const product = $('Pick Best Match').first().json;
const formatInsufficient = new Function('input', 'product', "
return {
  chat_id: input.chat_id,
  customer_ui_state: 'CART_ACTIVE',
  message_type: 'button',
  body_text: 'Only ' + product.stock + ' ' + (product.unit || 'units') + ' of ' + product.item_name + ' are available. You asked for ' + Number(product.requested_quantity || 1) + '.',
  buttons: [
    { id: 'view_cart', title: 'View Cart' },
    { id: 'start_shopping', title: 'Shop Items' },
  ],
};
");
return [{ json: formatInsufficient(input, product) }];

const items = $input.all().map(i => i.json);
const total = items.reduce((sum, item) => sum + Number(item.line_total || 0), 0);
return [{ json: { cart_total: total, item_count: items.length } }];

const product = $('Pick Best Match').first().json;
const input = $('Normalize Search Term').first().json;
const total = Number($('Build Cart Total').first().json.cart_total || 0);
const enablePricing = $('Search Products').first().json.enable_pricing !== false;
const qty = Number(product.requested_quantity || input.quantity || 1);
const price = Number(product.price || 0);
const lineTotal = (price * qty).toFixed(0);
const unit = product.unit ? ' ' + product.unit : '';
const mode = String(input.mode || 'add').toLowerCase();

let bodyText;
if (mode === 'remove') {
  bodyText = 'Removed from cart\n\n• ' + product.item_name + ' × ' + qty + unit;
} else {
  const priceStr = enablePricing ? ' — ₹' + lineTotal : '';
  bodyText = '✅ Added to cart\n\n• ' + product.item_name + ' × ' + qty + unit + priceStr;
}
if (total > 0 && enablePricing) {
  bodyText += '\n\nCart total: ₹' + total.toFixed(0);
}

return [{ json: {
  chat_id: input.chat_id,
  customer_ui_state: 'CART_ACTIVE',
  message_type: 'button',
  body_text: bodyText,
  buttons: [
    { id: 'view_cart', title: '🛒 View Cart' },
    { id: 'checkout', title: '✓ Checkout' },
  ],
} }];

const base = $('Format Add Success').first().json;
let promoHint = '';
try {
  promoHint = $('exec_promo_hint').first().json.promo_hint || '';
} catch(e) {}

const finalText = promoHint
  ? base.body_text + '\n\n' + promoHint
  : base.body_text;

return [{ json: { ...base, body_text: finalText } }];

